import React, { useEffect } from 'react';

export default function DynamicFavicon() {

  useEffect(() => {
    const goldLight = "#F5D76E"; // Dourado mais brilhante para nitidez
    const goldDark = "#B8860B";  
    const blackBG = "#000000";

    const svgString = `
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100">
        <defs>
          <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" style="stop-color:${goldLight};" />
            <stop offset="100%" style="stop-color:${goldDark};" />
          </linearGradient>
        </defs>

        <rect x="0" y="0" width="100" height="100" rx="20" fill="${blackBG}"/>

        <g transform="rotate(-45 50 50)" fill="url(#goldGrad)">

          <path d="M50 48 L90 48 L90 52 L50 52 Z" />

          <path d="M50 48 L90 48 L90 52 L50 52 Z" transform="rotate(20 50 50)" />

          <circle cx="50" cy="50" r="6" />

          <path d="M45 50 L15 35" stroke="url(#goldGrad)" stroke-width="12" stroke-linecap="round" />
          <path d="M45 50 L15 65" stroke="url(#goldGrad)" stroke-width="12" stroke-linecap="round" />

          <circle cx="15" cy="30" r="10" stroke="url(#goldGrad)" stroke-width="8" fill="none" />
          <circle cx="15" cy="70" r="10" stroke="url(#goldGrad)" stroke-width="8" fill="none" />
        </g>
      </svg>
    `;

    const svgBase64 = `data:image/svg+xml;base64,${btoa(svgString)}`;

    let link = document.querySelector("link[rel~='icon']");
    if (!link) {
      link = document.createElement('link');
      link.rel = 'icon';
      document.getElementsByTagName('head')[0].appendChild(link);
    }

    link.href = svgBase64;
    link.type = "image/svg+xml";

  }, []);

  return null;
}
